SourceCode.Declaration:
/// <summary>
/// This class is used for setup Bacthjob process.
/// </summary>
class ETGTrackingCustPaymController extends SysOperationServiceController
{
}

Method.Source:
/// <summary>
/// This method will execute the process method from Service class.
/// </summary>
protected void new()
{
    super(classStr(ETGTrackingCustPaymService), methodStr(ETGTrackingCustPaymService, process), SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// This method will return the Caption of the batch job.
/// </summary>
/// <returns>classDescription</returns>
public classDescription defaultCaption()
{
    return "@ETG_New:CustomerPaymentJournal";
}

/// <summary>
/// This method will return the controller.
/// </summary>
/// <param name = "_executionMode">ExecutionMode.</param>
/// <returns>ETGTrackingCustPaymController</returns>
public static ETGTrackingCustPaymController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    ETGTrackingCustPaymController controller;
    controller = new ETGTrackingCustPaymController();
    controller.parmExecutionMode(_executionMode);
    return controller;
}

/// <summary>
/// Class entry point. The system will call this method when a designated menu
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    ETGTrackingCustPaymController controller;
    controller = ETGTrackingCustPaymController::construct();
    controller.parmArgs(_args);
    controller.startOperation();
}
